type LoginMethod = "wallet" | "api";
type KeyScope = "read" | "read,trading";

interface StoredAdminApiKey {
  accountId?: string;
  key?: string;
  token?: string;
  secret?: string;
  brokerId?: string;
  env?: string;
  dexCreatorEnv?: string;
  expiresAt?: string;
  ownerWalletAddress?: string;
  rememberSigningKey?: boolean;
}

interface KeyInfoResponse {
  success?: boolean;
  message?: string;
  data?: unknown;
  rows?: unknown;
  [key: string]: unknown;
}

interface ManagedApiKey {
  id: string;
  key: string;
  scope: string;
  expiration?: unknown;
  ipRestrictions: string[];
  raw: Record<string, unknown>;
}

interface CreatedKeyCredentials {
  accountId: string;
  apiKey: string;
  secretKey: string;
  ip: string;
  permissions: string;
}

const MESSAGE_TYPES = {
  AddOrderlyKey: [
    { name: "brokerId", type: "string" },
    { name: "chainId", type: "uint256" },
    { name: "orderlyKey", type: "string" },
    { name: "scope", type: "string" },
    { name: "timestamp", type: "uint64" },
    { name: "expiration", type: "uint64" },
  ],
};

const KEY_EXPIRATION_MS = 1_000 * 60 * 60 * 24 * 365;
const NEW_KEY_SCOPE: KeyScope = "read";

function isAmbassadorProfile(profile: Profile | null) {
  return profile?.role === "ambassador" || profile?.brokerId === "ambassador";
}

function getLoginMethod(): LoginMethod | null {
  if (typeof window === "undefined") return null;
  const raw = walletGetItem("orderlyLoginContext");
  if (!raw) return null;
  try {
    const ctx = JSON.parse(raw) as { method?: LoginMethod };
    return ctx.method || null;
  } catch {
    return null;
  }
}

function getStoredKey(): StoredAdminApiKey | null {
  return readStoredAdminApiKey() as StoredAdminApiKey | null;
}

function getOrderlyAccountId(address: string, brokerId: string) {
  return keccak256(
    AbiCoder.defaultAbiCoder().encode(
      ["address", "bytes32"],
      [address, solidityPackedKeccak256(["string"], [brokerId])]
    )
  );
}

function stringValue(value: unknown): string | undefined {
  return typeof value === "string" && value.trim() ? value.trim() : undefined;
}

function withEd25519Prefix(value?: string) {
  const normalized = value?.trim();
  if (!normalized) return "";
  return normalized.toLowerCase().startsWith("ed25519:")
    ? normalized
    : `ed25519:${normalized}`;
}

function withoutEd25519Prefix(value?: string) {
  return value?.trim().replace(/^ed25519:/i, "") || "";
}

function orderlyKeyParam(value?: string) {
  return withEd25519Prefix(value);
}

function orderlyKeyQueryParam(value?: string) {
  return orderlyKeyParam(value);
}

function mask(value?: string, start = 12, end = 8) {
  if (!value) return "-";
  if (value.length <= start + end + 3) return value;
  return `${value.slice(0, start)}...${value.slice(-end)}`;
}

function formatTime(value: unknown, fallback = "Not available") {
  if (value === undefined || value === null || value === "") return fallback;
  const numeric =
    typeof value === "number"
      ? value
      : typeof value === "string" && /^\d+$/.test(value)
        ? Number(value)
        : NaN;
  const timestamp = Number.isFinite(numeric)
    ? numeric < 10_000_000_000
      ? numeric * 1000
      : numeric
    : Date.parse(String(value));
  if (!Number.isFinite(timestamp)) return fallback;
  return new Date(timestamp).toLocaleString();
}

function formatScope(scope?: string) {
  if (scope === "read,trading") return "Read + trading";
  if (scope === "read") return "Read only";
  return scope || "Unknown";
}

function formatPermissions(scope?: string) {
  if (scope === "read,trading") return "Read, Trading";
  if (scope === "read") return "Read";
  return scope || "Unknown";
}

function isIpRestrictionEntry(value: string) {
  const entry = value.trim();
  if (
    !entry ||
    /^(-|--|all|any|allow_all|none)$/i.test(entry) ||
    /all\s+ips\s+are\s+legal/i.test(entry)
  )
    return false;
  return (
    /^(\d{1,3}\.){3}\d{1,3}(\/\d{1,2})?$/.test(entry) ||
    (entry.includes(":") && /^[0-9a-f:]+(\/\d{1,3})?$/i.test(entry))
  );
}

function normalizeIpList(value: unknown): string[] {
  if (!value) return [];
  if (Array.isArray(value)) {
    return Array.from(new Set(value.flatMap(entry => normalizeIpList(entry))));
  }
  if (typeof value === "string") {
    return Array.from(
      new Set(
        value
          .split(/[\s,]+/)
          .map(entry => entry.trim())
          .filter(isIpRestrictionEntry)
      )
    );
  }
  if (typeof value === "object") {
    const obj = value as Record<string, unknown>;
    return normalizeIpList(
      obj.ip_restriction_list ??
        obj.ip_restrictions ??
        obj.ip_restriction ??
        obj.rows ??
        obj.data
    );
  }
  return [];
}

function parseIpInput(value: string) {
  return Array.from(
    new Set(
      value
        .split(/[\s,]+/)
        .map(entry => entry.trim())
        .filter(Boolean)
    )
  );
}

function collectKeyRows(value: unknown): Record<string, unknown>[] {
  if (!value) return [];
  if (Array.isArray(value))
    return value.flatMap(entry => collectKeyRows(entry));
  if (typeof value !== "object") return [];

  const obj = value as Record<string, unknown>;
  if (obj.orderly_key || obj.orderlyKey || obj.key) return [obj];

  return [
    "rows",
    "data",
    "key_info",
    "key_infos",
    "keys",
    "orderly_keys",
  ].flatMap(key => collectKeyRows(obj[key]));
}

function normalizeKeyRow(row: Record<string, unknown>): ManagedApiKey | null {
  const key = withEd25519Prefix(
    stringValue(row.orderly_key) ||
      stringValue(row.orderlyKey) ||
      stringValue(row.key)
  );
  if (!key) return null;
  return {
    id: key,
    key,
    scope: stringValue(row.scope) || stringValue(row.key_scope) || "Unknown",
    expiration:
      row.expiration ?? row.expired_at ?? row.expiration_time ?? row.expires_at,
    ipRestrictions: normalizeIpList(
      row.ip_restriction_list ?? row.ip_restrictions ?? row.ip_restriction
    ),
    raw: row,
  };
}

function normalizeKeyRows(payload: KeyInfoResponse): ManagedApiKey[] {
  const seen = new Set<string>();
  return collectKeyRows(payload)
    .map(normalizeKeyRow)
    .filter((row): row is ManagedApiKey => Boolean(row))
    .filter(row => {
      if (seen.has(row.id)) return false;
      seen.add(row.id);
      return true;
    });
}

function localStoredKeyToManaged(
  stored: StoredAdminApiKey
): ManagedApiKey | null {
  const key = withEd25519Prefix(stored.key || stored.token);
  if (!key) return null;
  return {
    id: key,
    key,
    scope: NEW_KEY_SCOPE,
    expiration: stored.expiresAt,
    ipRestrictions: [],
    raw: { local: true },
  };
}

function ensureSuccess(payload: unknown, fallback: string) {
  if (
    payload &&
    typeof payload === "object" &&
    "success" in payload &&
    (payload as { success?: boolean }).success === false
  ) {
    throw new Error(
      String((payload as { message?: unknown }).message || fallback)
    );
  }
}

function clearLocalKeyIfCurrent(
  removedKey: string,
  setStoredKey: (value: StoredAdminApiKey | null) => void
) {
  if (typeof window === "undefined") return;
  const stored = getStoredKey();
  const storedPublicKey = stored?.key || stored?.token;
  if (
    !storedPublicKey ||
    withEd25519Prefix(storedPublicKey) !== withEd25519Prefix(removedKey)
  )
    return;

  const envConfig = getOrderlyEnvConfig();
  walletRemoveItem("orderlyApiKey");
  if (stored.accountId) {
    const envs = Array.from(
      new Set(
        [
          envConfig.env,
          envConfig.dexCreatorEnv,
          stored.env,
          stored.dexCreatorEnv,
        ].filter(Boolean)
      )
    );
    envs.forEach(env =>
      window.localStorage.removeItem(
        `orderly-one:key:${stored.accountId}:${env}`
      )
    );
  }
  setStoredKey(null);
  window.dispatchEvent(new CustomEvent("authChanged"));
}

