export default function ApiKeysPage() {
  const { t } = useTranslation();
  const { address } = useAccount();
  const chainId = useChainId();
  const { data: walletClient } = useWalletClient();
  const [loginMethod, setLoginMethod] = useState<LoginMethod | null>(null);
  const [profile, setProfile] = useState<Profile | null>(null);
  const [storedKey, setStoredKey] = useState<StoredAdminApiKey | null>(null);
  const [keys, setKeys] = useState<ManagedApiKey[]>([]);
  const [initialized, setInitialized] = useState(false);
  const [ipInput, setIpInput] = useState("");
  const [ipRestrictionsEnabled, setIpRestrictionsEnabled] = useState(false);
  const [loading, setLoading] = useState(false);
  const [ipLoading, setIpLoading] = useState(false);
  const [creating, setCreating] = useState(false);
  const [createKeyModalOpen, setCreateKeyModalOpen] = useState(false);
  const [validatingKeyId, setValidatingKeyId] = useState("");
  const [savingIps, setSavingIps] = useState(false);
  const [removingKeyId, setRemovingKeyId] = useState("");
  const [deleteTarget, setDeleteTarget] = useState<ManagedApiKey | null>(null);
  const [ipEditTarget, setIpEditTarget] = useState<ManagedApiKey | null>(null);
  const [createdCredentials, setCreatedCredentials] =
    useState<CreatedKeyCredentials | null>(null);
  const [copiedKeyId, setCopiedKeyId] = useState("");
  const [rememberNewSigningKey, setRememberNewSigningKey] = useState(true);
  const copyResetTimer = useRef<number | null>(null);

  const isWalletLogin = loginMethod === "wallet";
  const envConfig = getOrderlyEnvConfig();
  const brokerId =
    profile?.brokerId || (profile?.role === "ambassador" ? "ambassador" : null);
  const accountId =
    storedKey?.accountId ||
    (address && brokerId ? getOrderlyAccountId(address, brokerId) : "");
  const currentLocalKey = withEd25519Prefix(storedKey?.key || storedKey?.token);
  const hasAdminAccess =
    isAmbassadorProfile(profile) || profile?.adminRegistered === true;
  const isMultisigAdmin =
    profile?.adminType === "multisig" && Boolean(profile?.multisigAddress);
  const canCreateKey =
    hasAdminAccess &&
    isWalletLogin &&
    Boolean(address && walletClient && brokerId) &&
    !isMultisigAdmin;
  const canUseSignedKey =
    hasAdminAccess &&
    isWalletLogin &&
    Boolean(storedKey?.accountId && storedKey?.secret);

  function showError(message: string) {
    toast({ title: message, variant: "destructive" });
  }

  useEffect(() => {
    function refreshLocalState() {
      setLoginMethod(getLoginMethod());
      setProfile(getProfile());
      setStoredKey(getStoredKey());
      setInitialized(true);
    }

    refreshLocalState();
    window.addEventListener("authChanged", refreshLocalState);
    window.addEventListener("storage", refreshLocalState);
    return () => {
      window.removeEventListener("authChanged", refreshLocalState);
      window.removeEventListener("storage", refreshLocalState);
      if (copyResetTimer.current) window.clearTimeout(copyResetTimer.current);
    };
  }, []);

  useEffect(() => {
    if (isAmbassadorProfile(getProfile())) return;

    let cancelled = false;
    fetchDexCreatorDexStatus()
      .then(status => {
        if (cancelled || !status || status.exists === false) return;
        setProfile(current => ({
          ...(current || {}),
          brokerId: status.brokerId || current?.brokerId,
          integrationType: status.integrationType || current?.integrationType,
          pathway:
            status.integrationType === "low_code"
              ? "low-code"
              : status.integrationType === "custom"
                ? "sdk"
                : current?.pathway,
          graduated: Boolean(status.isGraduated || current?.graduated),
          adminRegistered: Boolean(
            status.isGraduated || current?.adminRegistered
          ),
        }));
      })
      .catch(() => {
        // Local profile state is enough for key management when dex status is unavailable.
      });

    return () => {
      cancelled = true;
    };
  }, []);

  const refreshKeys = useCallback(
    async (quiet = false) => {
      if (!isWalletLogin) {
        setKeys([]);
        return;
      }

      const freshStoredKey = getStoredKey();
      setStoredKey(freshStoredKey);
      if (!freshStoredKey?.accountId || !freshStoredKey.secret) {
        setKeys([]);
        return;
      }

      if (!quiet) setLoading(true);
      try {
        const response = await signedAdminRequest<KeyInfoResponse>({
          endpoint: "/v1/client/key_info",
        });
        ensureSuccess(response, "Failed to load API key information.");
        let nextKeys = normalizeKeyRows(response);
        const localKey = localStoredKeyToManaged(freshStoredKey);
        if (!nextKeys.length && localKey) nextKeys = [localKey];
        setKeys(nextKeys);
      } catch (err) {
        showError(
          err instanceof Error
            ? err.message
            : "Failed to load API key information."
        );
      } finally {
        if (!quiet) setLoading(false);
      }
    },
    [isWalletLogin]
  );

  useEffect(() => {
    if (!isWalletLogin) return;
    void refreshKeys();
  }, [isWalletLogin, refreshKeys, storedKey?.accountId, storedKey?.secret]);

  useEffect(() => {
    if (!ipEditTarget) return;

    setIpInput(ipEditTarget.ipRestrictions.join(", "));
    setIpRestrictionsEnabled(ipEditTarget.ipRestrictions.length > 0);
    if (!canUseSignedKey) return;

    let cancelled = false;
    setIpLoading(true);
    signedAdminRequest<KeyInfoResponse>({
      endpoint: `/v1/client/orderly_key_ip_restriction?orderly_key=${orderlyKeyQueryParam(ipEditTarget.key)}`,
    })
      .then(response => {
        ensureSuccess(response, "Failed to load IP restrictions.");
        const ips = normalizeIpList(response);
        if (cancelled) return;
        setIpInput(ips.join(", "));
        setIpRestrictionsEnabled(ips.length > 0);
        setKeys(current =>
          current.map(key =>
            key.id === ipEditTarget.id ? { ...key, ipRestrictions: ips } : key
          )
        );
        setIpEditTarget(current =>
          current?.id === ipEditTarget.id
            ? { ...current, ipRestrictions: ips }
            : current
        );
      })
      .catch(err => {
        if (!cancelled)
          showError(
            err instanceof Error
              ? err.message
              : "Failed to load IP restrictions."
          );
      })
      .finally(() => {
        if (!cancelled) setIpLoading(false);
      });

    return () => {
      cancelled = true;
    };
  }, [canUseSignedKey, ipEditTarget?.id, ipEditTarget?.key]);

  async function createOrderlyApiKey() {
    if (isMultisigAdmin) {
      showError(
        "This admin account uses a multisig signer. Create its API key from the delegate-signer banner at the top of the dashboard."
      );
      return;
    }
    if (!isWalletLogin) {
      showError(
        "Sign in with wallet connect before managing Orderly API keys."
      );
      return;
    }
    if (!address || !walletClient) {
      showError("Connect a wallet before creating an Orderly API key.");
      return;
    }
    if (!brokerId) {
      showError(
        "Create or load a builder profile before creating an Orderly API key."
      );
      return;
    }

    setCreating(true);
    try {
      const signer = await walletClientToEthersSigner(walletClient);
      const privateKey = randomBytes(32);
      const orderlyKey = `ed25519:${bs58.encode(await getPublicKeyAsync(privateKey))}`;
      const timestamp = Date.now();
      const expiresAt = timestamp + KEY_EXPIRATION_MS;
      const orderlyAccountId = getOrderlyAccountId(address, brokerId);
      const messageBody = {
        brokerId,
        chainId: Number(chainId || 1),
        orderlyKey,
        scope: NEW_KEY_SCOPE,
        timestamp,
        expiration: expiresAt,
      };
      const signature = await signer.signTypedData(
        getOffChainDomain(chainId || 1),
        MESSAGE_TYPES,
        messageBody
      );
      const data = await apiClient<{ success?: boolean; message?: string }>({
        endpoint: "/v1/orderly_key",
        method: "POST",
        token: null,
        body: {
          message: messageBody,
          signature,
          userAddress: address,
        },
        showToastOnError: false,
      });
      if (data.success === false)
        throw new Error(data.message || "Failed to create Orderly API key.");

      const secret = bs58.encode(privateKey);
      const publicKey = withoutEd25519Prefix(orderlyKey);
      const nextStoredKey: StoredAdminApiKey = {
        accountId: orderlyAccountId,
        key: publicKey,
        token: publicKey,
        secret,
        brokerId,
        env: envConfig.env,
        dexCreatorEnv: envConfig.dexCreatorEnv,
        ownerWalletAddress: address,
        rememberSigningKey: rememberNewSigningKey,
        expiresAt: new Date(expiresAt).toISOString(),
      };
      saveDexCreatorStyleOrderlyKey(orderlyAccountId, secret);
      walletSetItem("orderlyApiKey", JSON.stringify(nextStoredKey));
      window.dispatchEvent(new CustomEvent("authChanged"));
      setStoredKey(nextStoredKey);
      const managedKey: ManagedApiKey = {
        id: orderlyKey,
        key: orderlyKey,
        scope: NEW_KEY_SCOPE,
        expiration: expiresAt,
        ipRestrictions: [],
        raw: { local: true },
      };
      setKeys(current => [
        managedKey,
        ...current.filter(key => key.id !== managedKey.id),
      ]);
      setCreatedCredentials({
        accountId: orderlyAccountId,
        apiKey: orderlyKey,
        secretKey: withEd25519Prefix(secret),
        ip: "--",
        permissions: formatPermissions(NEW_KEY_SCOPE),
      });
      setCreateKeyModalOpen(false);
      void refreshKeys(true);
    } catch (err) {
      showError(
        err instanceof Error ? err.message : "Failed to create Orderly API key."
      );
    } finally {
      setCreating(false);
    }
  }

  async function validateKey(key: ManagedApiKey) {
    if (!accountId || !key.key) {
      showError("Create or select an Orderly API key before validating it.");
      return;
    }

    setValidatingKeyId(key.id);
    try {
      const data = await apiClient<{ success?: boolean; message?: string }>({
        endpoint: `/v1/get_orderly_key?account_id=${encodeURIComponent(accountId)}&orderly_key=${orderlyKeyQueryParam(key.key)}`,
        token: null,
        showToastOnError: false,
      });
      if (data.success === false)
        throw new Error(data.message || "Orderly key validation failed.");
      toast({ title: data.message || "Orderly key validation succeeded." });
    } catch (err) {
      toast({
        title:
          err instanceof Error ? err.message : "Orderly key validation failed.",
        variant: "destructive",
      });
    } finally {
      setValidatingKeyId("");
    }
  }

  async function saveIpRestrictions() {
    if (!ipEditTarget) return;
    const ips = parseIpInput(ipInput);
    setSavingIps(true);
    try {
      const response = await signedAdminRequest<KeyInfoResponse>({
        endpoint:
          ipRestrictionsEnabled && ips.length
            ? "/v1/client/set_orderly_key_ip_restriction"
            : "/v1/client/reset_orderly_key_ip_restriction",
        method: "POST",
        data:
          ipRestrictionsEnabled && ips.length
            ? {
                orderly_key: orderlyKeyParam(ipEditTarget.key),
                ip_restriction_list: ips.join(","),
              }
            : { orderly_key: orderlyKeyParam(ipEditTarget.key) },
      });
      ensureSuccess(response, "Failed to update IP restrictions.");
      const nextIps = ipRestrictionsEnabled && ips.length ? ips : [];
      setIpInput(nextIps.join(", "));
      setIpRestrictionsEnabled(nextIps.length > 0);
      setKeys(current =>
        current.map(key =>
          key.id === ipEditTarget.id ? { ...key, ipRestrictions: nextIps } : key
        )
      );
      setIpEditTarget(current =>
        current ? { ...current, ipRestrictions: nextIps } : current
      );
      toast({
        title: nextIps.length
          ? "IP restrictions updated."
          : "IP restrictions reset.",
      });
    } catch (err) {
      showError(
        err instanceof Error ? err.message : "Failed to update IP restrictions."
      );
    } finally {
      setSavingIps(false);
    }
  }

  async function removeKey(key: ManagedApiKey) {
    setRemovingKeyId(key.id);
    try {
      const response = await signedAdminRequest<KeyInfoResponse>({
        endpoint: "/v1/client/remove_orderly_key",
        method: "POST",
        data: { orderly_key: orderlyKeyParam(key.key) },
      });
      ensureSuccess(response, "Failed to remove Orderly API key.");
      clearLocalKeyIfCurrent(key.key, setStoredKey);
      setKeys(current => current.filter(item => item.id !== key.id));
      setDeleteTarget(null);
      toast({ title: "Orderly API key removed." });
    } catch (err) {
      showError(
        err instanceof Error ? err.message : "Failed to remove Orderly API key."
      );
    } finally {
      setRemovingKeyId("");
    }
  }

  async function copyKey(key: ManagedApiKey) {
    try {
      await navigator.clipboard.writeText(key.key);
      setCopiedKeyId(key.id);
      toast({ title: "Copied key to clipboard." });
      if (copyResetTimer.current) window.clearTimeout(copyResetTimer.current);
      copyResetTimer.current = window.setTimeout(
        () => setCopiedKeyId(""),
        1800
      );
    } catch {
      showError("Clipboard permission denied.");
    }
  }

  async function copyCreatedKeyInfo() {
    if (!createdCredentials) return;
    const text = [
      "API key created",
      "Account ID",
      createdCredentials.accountId,
      "API key",
      createdCredentials.apiKey,
      "Secret key",
      createdCredentials.secretKey,
      "IP",
      createdCredentials.ip,
      "Permissions",
      createdCredentials.permissions,
    ].join("\n");

    try {
      await navigator.clipboard.writeText(text);
      toast({ title: "API info copied." });
    } catch {
      showError("Clipboard permission denied.");
    }
  }

  if (!initialized) return <ApiKeysPageSkeleton />;

  if (!hasAdminAccess) {
    return (
      <PageShell
        pageTitle={t("settings.apiKeyManagement")}
        parentTitle={t("navigation.settings")}
        parentHref="/settings"
      >
        <section className="rounded-xl border border-[rgba(217,171,82,0.28)] bg-[rgba(217,171,82,0.08)] p-6">
          <div className="flex items-start gap-3">
            <AlertTriangle className="mt-0.5 h-5 w-5 shrink-0 text-(--fg-warning)" />
            <div>
              <h2 className="text-base font-medium text-(--fg-primary)">
                Admin account registration required
              </h2>
              <p className="mt-1 text-sm leading-6 text-(--fg-secondary)">
                Finish admin setup before managing Orderly API keys for signed
                admin requests.
              </p>
              <LocalizedLink
                to="/admin-setup"
                className="mt-4 inline-flex rounded-full px-5 py-2.5 text-sm font-medium text-(--fg-primary) transition-opacity hover:opacity-90"
                style={{ background: "var(--bg-brand-grad)" }}
              >
                Finish admin setup
              </LocalizedLink>
            </div>
          </div>
        </section>
      </PageShell>
    );
  }

  return (
    <PageShell
      pageTitle={t("settings.apiKeyManagement")}
      parentTitle={t("navigation.settings")}
      parentHref="/settings"
    >
      <div className="space-y-6">
        <section className="rounded-xl border border-(--line-subtle) bg-(--bg-surface-primary) p-6">
          <div className="mb-5 flex flex-col gap-4 md:flex-row md:items-start md:justify-between">
            <div className="flex items-start gap-3">
              <div className="flex h-10 w-10 shrink-0 items-center justify-center rounded-xl bg-[rgba(188,135,255,0.12)] text-(--fg-brand)">
                <KeyRound className="h-5 w-5" />
              </div>
              <div>
                <h2 className="text-lg font-medium text-(--fg-primary)">
                  {t("settings.apiKeyManagement")}
                </h2>
                <p className="max-w-2xl text-sm text-(--fg-secondary)">
                  Create, validate, remove, and restrict Orderly API keys for
                  the connected builder account. Key management is available
                  only for wallet-connect sessions.
                </p>
              </div>
            </div>
            <button
              type="button"
              disabled={!canUseSignedKey || loading}
              onClick={() => void refreshKeys()}
              className="inline-flex items-center justify-center gap-2 rounded-lg border border-(--line-subtle) px-4 py-2 text-sm font-medium text-(--fg-primary) transition-colors hover:bg-(--bg-hover) disabled:cursor-not-allowed disabled:opacity-50"
            >
              <RefreshCw
                className={`h-4 w-4 ${loading ? "animate-spin" : ""}`}
              />
              Refresh
            </button>
          </div>

          <div className="grid grid-cols-1 gap-3 md:grid-cols-3">
            <InfoCard
              icon={ShieldCheck}
              label="Access"
              value={
                isWalletLogin
                  ? "Wallet session"
                  : loginMethod === "api"
                    ? "API-key session"
                    : "Unknown"
              }
            />
            <InfoCard
              icon={Wallet}
              label="Account ID"
              value={mask(accountId || storedKey?.accountId)}
              mono
            />
            <InfoCard
              icon={KeyRound}
              label="Local key"
              value={currentLocalKey ? mask(currentLocalKey) : "Not stored"}
              mono
            />
          </div>
        </section>

        {!isWalletLogin ? (
          <section className="rounded-xl border border-[rgba(255,99,144,0.25)] bg-[rgba(255,99,144,0.08)] p-6">
            <div className="flex items-start gap-3">
              <AlertTriangle className="mt-0.5 h-5 w-5 shrink-0 text-[#FF6390]" />
              <div>
                <h3 className="text-base font-medium text-[#FF6390]">
                  Wallet login required
                </h3>
                <p className="mt-1 text-sm text-(--fg-secondary)">
                  API-key login can sign admin requests, but it cannot create,
                  remove, or change Orderly keys. Sign out and connect the
                  builder wallet to manage keys.
                </p>
              </div>
            </div>
          </section>
        ) : (
          <>
            <section className="rounded-xl border border-(--line-subtle) bg-(--bg-surface-primary) p-6">
              <div className="mb-4 flex flex-col gap-3 md:flex-row md:items-center md:justify-between">
                <div>
                  <h3 className="text-base font-medium text-(--fg-primary)">
                    Orderly keys
                  </h3>
                </div>
                <OdsButton
                  type="button"
                  variant="primary"
                  size="medium"
                  disabled={!canCreateKey || creating}
                  onClick={() => setCreateKeyModalOpen(true)}
                  className="w-full gap-2 md:w-auto"
                >
                  <Plus className="h-4 w-4" />
                  Create key
                </OdsButton>
              </div>

              {isMultisigAdmin && (
                <OdsAlert type="info" className="mb-4">
                  This admin account is secured by a multisig signer (
                  <span className="font-mono">{profile?.multisigAddress}</span>
                  ). Its API key is created through the delegate-signer flow.
                  Use the &ldquo;Create API key&rdquo; banner at the top of the
                  dashboard, which will switch your wallet to the
                  multisig&rsquo;s network and sign on its behalf.
                </OdsAlert>
              )}

              {loading ? (
                <ApiKeyListSkeleton />
              ) : !canUseSignedKey ? (
                <div className="rounded-lg border border-dashed border-(--line-subtle) p-6 text-sm text-(--fg-secondary)">
                  No complete local Orderly key is available. Create a
                  wallet-signed key before loading server-side key information.
                </div>
              ) : keys.length > 0 ? (
                <div className="space-y-3">
                  {keys.map(key => {
                    const local = currentLocalKey === key.key;
                    const ipPreview = key.ipRestrictions.length
                      ? key.ipRestrictions.slice(0, 3).join(", ")
                      : "Allow all IPs";
                    const extraIpCount = Math.max(
                      0,
                      key.ipRestrictions.length - 3
                    );
                    return (
                      <div
                        key={key.id}
                        className="rounded-xl border border-(--line-subtle) bg-(--bg-surface-secondary) p-4 transition-colors hover:border-(--line-strong)"
                      >
                        <div className="flex flex-col gap-4 xl:flex-row xl:items-start xl:justify-between">
                          <div className="min-w-0 flex-1">
                            <div className="mb-3 flex flex-wrap items-center gap-2">
                              {local && (
                                <span className="rounded-full bg-[rgba(74,222,128,0.12)] px-2 py-0.5 text-xs font-medium text-[#4ADE80]">
                                  Local signing key
                                </span>
                              )}
                              <span className="rounded-full bg-(--bg-hover) px-2 py-0.5 text-xs text-(--fg-secondary)">
                                {formatScope(key.scope)}
                              </span>
                            </div>
                            <div className="rounded-lg border border-(--line-subtle) bg-(--bg-input) px-3 py-2 font-mono text-sm font-medium text-(--fg-primary)">
                              {mask(key.key, 16, 10)}
                            </div>
                            <div className="mt-3 grid grid-cols-1 gap-2 md:grid-cols-2">
                              <KeyDetail label="Expires">
                                {formatTime(
                                  key.expiration,
                                  "No expiration shown"
                                )}
                              </KeyDetail>
                              <KeyDetail label="IP rules">
                                <span
                                  className={
                                    key.ipRestrictions.length
                                      ? "font-mono text-xs"
                                      : "text-(--fg-secondary)"
                                  }
                                >
                                  {ipPreview}
                                  {extraIpCount ? ` +${extraIpCount} more` : ""}
                                </span>
                              </KeyDetail>
                            </div>
                          </div>
                          <div className="flex shrink-0 items-center gap-2">
                            <button
                              type="button"
                              disabled={validatingKeyId === key.id}
                              onClick={() => void validateKey(key)}
                              className="rounded-lg border border-(--line-subtle) p-2 text-(--fg-secondary) transition-colors hover:bg-(--bg-hover) hover:text-(--fg-primary) disabled:cursor-not-allowed disabled:opacity-50"
                              aria-label="Validate key"
                            >
                              <ShieldCheck
                                className={`h-4 w-4 ${validatingKeyId === key.id ? "animate-pulse text-(--fg-brand)" : ""}`}
                              />
                            </button>
                            <button
                              type="button"
                              onClick={() => void copyKey(key)}
                              className="rounded-lg border border-(--line-subtle) p-2 text-(--fg-secondary) transition-colors hover:bg-(--bg-hover) hover:text-(--fg-primary)"
                              aria-label="Copy key"
                            >
                              {copiedKeyId === key.id ? (
                                <Check className="h-4 w-4 text-[#4ADE80]" />
                              ) : (
                                <Copy className="h-4 w-4" />
                              )}
                            </button>
                            <button
                              type="button"
                              onClick={() => {
                                setIpEditTarget(key);
                              }}
                              className="rounded-lg border border-(--line-subtle) p-2 text-(--fg-secondary) transition-colors hover:bg-(--bg-hover) hover:text-(--fg-primary)"
                              aria-label="Edit IP restrictions"
                            >
                              <Pencil className="h-4 w-4" />
                            </button>
                            <button
                              type="button"
                              disabled={removingKeyId === key.id}
                              onClick={() => setDeleteTarget(key)}
                              className="rounded-lg border border-[rgba(255,99,144,0.25)] p-2 text-[#FF6390] transition-colors hover:bg-[rgba(255,99,144,0.08)] disabled:cursor-not-allowed disabled:opacity-50"
                              aria-label="Remove key"
                            >
                              <Trash2 className="h-4 w-4" />
                            </button>
                          </div>
                        </div>
                      </div>
                    );
                  })}
                </div>
              ) : (
                <div className="rounded-lg border border-dashed border-(--line-subtle) p-6 text-sm text-(--fg-secondary)">
                  No Orderly keys returned for this account.
                </div>
              )}
            </section>
          </>
        )}
      </div>

      <Modal
        open={createKeyModalOpen}
        onClose={() => {
          if (!creating) setCreateKeyModalOpen(false);
        }}
        title="Create Orderly key"
      >
        <form
          className="space-y-5"
          onSubmit={event => {
            event.preventDefault();
            void createOrderlyApiKey();
          }}
        >
          <div className="mx-auto flex h-11 w-11 items-center justify-center rounded-xl bg-[var(--bg-primary-subtle)] text-[var(--fg-brand)]">
            <KeyRound className="h-5 w-5" />
          </div>
          <p className="text-center text-sm leading-5 text-[var(--fg-secondary)]">
            Generate an ed25519 key, sign the AddOrderlyKey message with your
            wallet, and store the private key locally for signed admin API
            requests.
          </p>

          <div className="rounded-lg border border-(--line-subtle) bg-(--bg-surface-secondary) px-3 py-2">
            <div className="text-[10px] font-medium uppercase tracking-[0.16em] text-(--fg-secondary)">
              Scope
            </div>
            <div className="mt-1 text-sm font-medium text-(--fg-primary)">
              Read only
            </div>
          </div>

          <label className="flex cursor-pointer items-start gap-3 rounded-lg border border-(--line-subtle) bg-(--bg-surface-secondary) px-3 py-2.5 text-left">
            <OdsCheckbox
              checked={rememberNewSigningKey}
              onCheckedChange={checked =>
                setRememberNewSigningKey(checked === true)
              }
              disabled={creating}
              className="mt-0.5"
            />
            <span className="text-sm leading-5 text-(--fg-secondary)">
              <span className="block font-medium text-(--fg-primary)">
                Remember this signing key on this device
              </span>
              Keep the local signing key after disconnecting. Turn this off on
              shared devices.
            </span>
          </label>

          {!brokerId && (
            <OdsAlert type="warning">
              No broker ID is loaded for this profile yet. Create or load a
              builder profile before creating a key.
            </OdsAlert>
          )}

          <div className="flex flex-col-reverse gap-3 sm:flex-row sm:justify-end">
            <OdsButton
              type="button"
              variant="secondary"
              size="large"
              disabled={creating}
              onClick={() => setCreateKeyModalOpen(false)}
              className="w-full sm:w-auto"
            >
              Cancel
            </OdsButton>
            <OdsButton
              type="submit"
              variant="primary"
              size="large"
              disabled={!canCreateKey || creating}
              className="w-full gap-2 sm:w-auto"
            >
              {creating ? (
                <span className="inline-block h-4 w-4 animate-spin rounded-full border-2 border-[var(--line-strong)] border-t-[var(--fg-base)]" />
              ) : (
                <Plus className="h-4 w-4" />
              )}
              {creating ? "Creating..." : "Create key"}
            </OdsButton>
          </div>
        </form>
      </Modal>

      <Modal
        open={Boolean(createdCredentials)}
        onClose={() => setCreatedCredentials(null)}
        title="API key created"
      >
        {createdCredentials && (
          <div className="space-y-5">
            <div className="space-y-3">
              <CredentialRow
                label="Account ID"
                value={createdCredentials.accountId}
              />
              <CredentialRow
                label="API key"
                value={createdCredentials.apiKey}
              />
              <CredentialRow
                label="Secret key"
                value={createdCredentials.secretKey}
              />
              <CredentialRow
                label="IP"
                value={createdCredentials.ip}
                mono={false}
              />
              <CredentialRow
                label="Permissions"
                value={createdCredentials.permissions}
                mono={false}
              />
            </div>
            <OdsAlert type="warning">
              Please copy the API secret. Once you close this pop-up, the API
              secret will be encrypted.
            </OdsAlert>
            <div className="flex flex-col-reverse gap-3 sm:flex-row sm:justify-end">
              <OdsButton
                type="button"
                variant="secondary"
                size="large"
                onClick={() => void copyCreatedKeyInfo()}
                className="w-full gap-2 sm:w-auto"
              >
                <Copy className="h-4 w-4" />
                Copy API info
              </OdsButton>
              <OdsButton
                type="button"
                variant="primary"
                size="large"
                onClick={() => setCreatedCredentials(null)}
                className="w-full sm:w-auto"
              >
                OK
              </OdsButton>
            </div>
          </div>
        )}
      </Modal>

      <Modal
        open={Boolean(ipEditTarget)}
        onClose={() => (savingIps ? undefined : setIpEditTarget(null))}
        title="Edit IP restrictions"
      >
        {ipEditTarget && (
          <div className="space-y-5">
            <div>
              <div className="mb-2 text-xs font-medium uppercase tracking-[0.16em] text-(--fg-secondary)">
                API key
              </div>
              <div className="rounded-lg border border-(--line-subtle) bg-(--bg-surface-secondary) p-3 font-mono text-xs text-(--fg-secondary)">
                {ipEditTarget.key}
              </div>
            </div>
            <label className="block">
              <div className="mb-2 flex items-center justify-between gap-3">
                <span className="text-xs font-medium uppercase tracking-[0.16em] text-(--fg-secondary)">
                  IP restrictions
                </span>
                {ipLoading && (
                  <span className="text-xs text-(--fg-secondary)">
                    Loading...
                  </span>
                )}
              </div>
              <div
                className={`mb-3 flex w-full items-center justify-between rounded-xl border px-4 py-3 text-left transition-colors ${
                  ipRestrictionsEnabled
                    ? "border-(--line-brand) bg-[rgba(188,135,255,0.10)]"
                    : "border-(--line-subtle) bg-(--bg-surface-secondary)"
                }`}
              >
                <span>
                  <span className="block text-sm font-medium text-(--fg-primary)">
                    Restrict this API key by IP
                  </span>
                  <span className="mt-0.5 block text-xs text-(--fg-secondary)">
                    {ipRestrictionsEnabled
                      ? "Only listed IPs can use this key."
                      : "Disabled. All IPs are allowed for this key."}
                  </span>
                </span>
                <OdsToggle
                  checked={ipRestrictionsEnabled}
                  onCheckedChange={checked => {
                    setIpRestrictionsEnabled(checked);
                    if (!checked) setIpInput("");
                  }}
                  aria-label="Restrict this API key by IP"
                />
              </div>
              <textarea
                value={ipInput}
                onChange={event => setIpInput(event.target.value)}
                disabled={!ipRestrictionsEnabled}
                rows={5}
                placeholder="Add IP addresses, separated by commas"
                className="w-full rounded-lg border border-(--line-subtle) bg-(--bg-input) px-3 py-2 font-mono text-sm text-(--fg-primary) outline-none transition-colors placeholder:font-sans placeholder:text-(--fg-placeholder) focus:border-(--line-brand) disabled:cursor-not-allowed disabled:opacity-50"
              />
            </label>
            {ipRestrictionsEnabled && (
              <p className="text-sm text-(--fg-secondary)">
                Add IP addresses, separated by commas.
              </p>
            )}
            <div className="flex flex-col gap-3 sm:flex-row sm:justify-end">
              <OdsButton
                type="button"
                variant="primary"
                size="large"
                disabled={!canUseSignedKey || savingIps}
                onClick={() => void saveIpRestrictions()}
                className="w-full gap-2 sm:w-auto"
              >
                {savingIps ? (
                  <span className="inline-block h-4 w-4 animate-spin rounded-full border-2 border-[var(--line-strong)] border-t-[var(--fg-base)]" />
                ) : (
                  <Save className="h-4 w-4" />
                )}
                {savingIps
                  ? "Saving..."
                  : ipRestrictionsEnabled
                    ? "Save"
                    : "Save as allow all"}
              </OdsButton>
            </div>
          </div>
        )}
      </Modal>

      <Modal
        open={Boolean(deleteTarget)}
        onClose={() => (removingKeyId ? undefined : setDeleteTarget(null))}
        title="Remove API key"
      >
        {deleteTarget && (
          <div className="space-y-5">
            <div className="rounded-xl border border-[rgba(255,99,144,0.25)] bg-[rgba(255,99,144,0.08)] p-4">
              <div className="mb-2 flex items-center gap-2 text-sm font-medium text-[#FF6390]">
                <AlertTriangle className="h-4 w-4" />
                Confirm key removal
              </div>
              <p className="text-sm text-(--fg-secondary)">
                This will remove the selected Orderly API key. If this is your
                local signing key, it will also be cleared from this browser.
              </p>
            </div>

            <div className="rounded-lg border border-(--line-subtle) bg-(--bg-surface-secondary) p-3 font-mono text-xs text-(--fg-secondary)">
              {deleteTarget.key}
            </div>

            <div className="flex flex-col-reverse gap-3 sm:flex-row sm:justify-end">
              <OdsButton
                type="button"
                variant="secondary"
                size="large"
                disabled={Boolean(removingKeyId)}
                onClick={() => setDeleteTarget(null)}
                className="w-full sm:w-auto"
              >
                Cancel
              </OdsButton>
              <button
                type="button"
                disabled={Boolean(removingKeyId)}
                onClick={() => void removeKey(deleteTarget)}
                className="w-full rounded-full bg-[#FF6390] px-5 py-2.5 text-sm font-semibold text-white transition-opacity hover:opacity-90 disabled:cursor-not-allowed disabled:opacity-50 sm:w-auto"
              >
                {removingKeyId ? "Removing..." : "Remove key"}
              </button>
            </div>
          </div>
        )}
      </Modal>
    </PageShell>
  );
}
